package com.cognizant.week5.mini;

import java.util.List; import org.springframework.web.bind.annotation.DeleteMapping; import org.springframework.web.bind.annotation.GetMapping; import org.springframework.web.bind.annotation.PathVariable; import org.springframework.web.bind.annotation.PostMapping; import org.springframework.web.bind.annotation.PutMapping; import org.springframework.web.bind.annotation.RequestBody; import org.springframework.web.bind.annotation.RequestMapping; import org.springframework.web.bind.annotation.RequestParam; import org.springframework.web.bind.annotation.RestController;
@RestController @RequestMapping("/employees") public class EmployeeController { private final EmployeeService service; public EmployeeController(EmployeeService service) { this.service = service; } @GetMapping public List<Employee> all() { return service.all(); } @PostMapping public Employee add(@RequestBody Employee employee) { return service.add(employee); } @PutMapping("/{id}") public Employee update(@PathVariable Long id, @RequestBody Employee employee) { return service.update(id, employee); } @DeleteMapping("/{id}") public void delete(@PathVariable Long id) { service.delete(id); } @GetMapping("/search") public List<Employee> search(@RequestParam String name) { return service.search(name); } @GetMapping("/department") public List<Employee> department(@RequestParam String name) { return service.department(name); } }
